INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench','Palms-Up Dumbbell Wrist Curl Over A Bench','antebrazos',ARRAY[]::text[],'mancuernas','strength',ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'],'Start out by placing two dumbbells on one side of a flat bench. Kneel down on both of your knees so that your body is facing the flat bench. Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge. Start out by curling your wrist upwards and exhaling. Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Your forearms should be stationary as your wrist is the only movement needed to perform this exercise. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg','exercisedb',true),('Parallel_Bar_Dip','Parallel Bar Dip','tríceps',ARRAY['pecho','hombros'],'otro','strength',ARRAY['Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out.','Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.','Reverse the motion by extending the elbow, pushing yourself back up into the starting position.','Repeat for the desired number of repetitions.'],'Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out. Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent. Reverse the motion by extending the elbow, pushing yourself back up into the starting position. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Parallel_Bar_Dip/0.jpg','exercisedb',true),('Pelvic_Tilt_Into_Bridge','Pelvic Tilt Into Bridge','espalda baja',ARRAY[]::text[],NULL,'stretching',ARRAY['Lie down with your feet on the floor, heels directly under your knees.','Lift only your tailbone to the ceiling to stretch your lower back. (Don''''t lift the entire spine yet.) Pull in your stomach.','To go into a bridge, lift the entire spine except the neck.'],'Lie down with your feet on the floor, heels directly under your knees. Lift only your tailbone to the ceiling to stretch your lower back. (Don''t lift the entire spine yet.) Pull in your stomach. To go into a bridge, lift the entire spine except the neck.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pelvic_Tilt_Into_Bridge/0.jpg','exercisedb',true),('Peroneals-SMR','Peroneals-SMR','pantorrillas',ARRAY[]::text[],'foam roller','stretching',ARRAY['Lay on your side, supporting your weight on your forearm and on a foam roller placed on the outside of your lower leg. Your upper leg can either be on top of your lower leg, or you can cross it in front of you. This will be your starting position.','Raise your hips off of the ground and begin to roll from below the knee to above the ankle on the side of your leg, pausing at points of tension for 10-30 seconds. Repeat on the other leg.'],'Lay on your side, supporting your weight on your forearm and on a foam roller placed on the outside of your lower leg. Your upper leg can either be on top of your lower leg, or you can cross it in front of you. This will be your starting position. Raise your hips off of the ground and begin to roll from below the knee to above the ankle on the side of your leg, pausing at points of tension for 10-30 seconds. Repeat on the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals-SMR/0.jpg','exercisedb',true),('Peroneals_Stretch','Peroneals Stretch','pantorrillas',ARRAY[]::text[],'otro','stretching',ARRAY['In a seated position, loop a belt, rope, or band around one foot. This will be your starting position.','With the leg extended and the heel off of the ground, pull on the belt so that the foot is inverted, with the inside of the foot being pulled towards you. Hold for 10-20 seconds, and then switch sides.'],'In a seated position, loop a belt, rope, or band around one foot. This will be your starting position. With the leg extended and the heel off of the ground, pull on the belt so that the foot is inverted, with the inside of the foot being pulled towards you. Hold for 10-20 seconds, and then switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals_Stretch/0.jpg','exercisedb',true),('Physioball_Hip_Bridge','Physioball Hip Bridge','glúteos',ARRAY['isquiotibiales'],'pelota de ejercicio','strength',ARRAY['Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position.','Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge.','Pause at the top of the motion and return to the starting position.'],'Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position. Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge. Pause at the top of the motion and return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Physioball_Hip_Bridge/0.jpg','exercisedb',true),('Pin_Presses','Pin Presses','tríceps',ARRAY['pecho','antebrazos','dorsales','espalda media','hombros'],'barra','powerlifting',ARRAY['Pin presses remove the eccentric phase of the bench press, developing starting strength. They also allow you to train a desired range of motion.','The bench should be set up in a power rack. Set the pins to the desired point in your range of motion, whether it just be lockout or an inch off of your chest. The bar should be moved to the pins and prepared for lifting.','Begin by lying on the bench, with the bar directly above the contact point during your regular bench. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.','You can take a standard bench grip, or shoulder width to focus on the triceps. The bar, wrist, and elbow should stay in line at all times. Focus on squeezing the bar and trying to pull it apart.','Drive the bar up with as much force as possible. The elbows should be tucked in until lockout.','Return the bar to the pins, pausing before beginning the next repetition.'],'Pin presses remove the eccentric phase of the bench press, developing starting strength. They also allow you to train a desired range of motion. The bench should be set up in a power rack. Set the pins to the desired point in your range of motion, whether it just be lockout or an inch off of your chest. The bar should be moved to the pins and prepared for lifting. Begin by lying on the bench, with the bar directly above the contact point during your regular bench. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. You can take a standard bench grip, or shoulder width to focus on the triceps. The bar, wrist, and elbow should stay in line at all times. Focus on squeezing the bar and trying to pull it apart. Drive the bar up with as much force as possible. The elbows should be tucked in until lockout. Return the bar to the pins, pausing before beginning the next repetition.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pin_Presses/0.jpg','exercisedb',true),('Piriformis-SMR','Piriformis-SMR','glúteos',ARRAY[]::text[],'foam roller','stretching',ARRAY['Sit with your buttocks on top of a foam roll. Bend your knees, and then cross one leg so that the ankle is over the knee. This will be your starting position.','Shift your weight to the side of the crossed leg, rolling over the buttocks until you feel tension in your upper glute. You may assist the stretch by using one hand to pull the bent knee towards your chest. Hold this position for 10-30 seconds, and then switch sides.'],'Sit with your buttocks on top of a foam roll. Bend your knees, and then cross one leg so that the ankle is over the knee. This will be your starting position. Shift your weight to the side of the crossed leg, rolling over the buttocks until you feel tension in your upper glute. You may assist the stretch by using one hand to pull the bent knee towards your chest. Hold this position for 10-30 seconds, and then switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Piriformis-SMR/0.jpg','exercisedb',true),('Plank','Plank','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY['Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.','Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised.'],'Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder. Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plank/0.jpg','exercisedb',true),('Plate_Pinch','Plate Pinch','antebrazos',ARRAY[]::text[],'otro','strength',ARRAY['Grab two wide-rimmed plates and put them together with the smooth sides facing outward','Use your fingers to grip the outside part of the plate and your thumb for the other side thus holding both plates together. This is the starting position.','Squeeze the plate with your fingers and thumb. Hold this position for as long as you can.','Repeat for the recommended amount of sets prescribed in your program.','Switch arms and repeat the movements.'],'Grab two wide-rimmed plates and put them together with the smooth sides facing outward Use your fingers to grip the outside part of the plate and your thumb for the other side thus holding both plates together. This is the starting position. Squeeze the plate with your fingers and thumb. Hold this position for as long as you can. Repeat for the recommended amount of sets prescribed in your program. Switch arms and repeat the movements.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Pinch/0.jpg','exercisedb',true);